    <h3>Shipping Information</h3>

    <label>
        Name
        <input @bind="Shipping.Name" @bind:event="oninput" />
    </label>

    <label>
        Address
        <input @bind="Shipping.Address" @bind:event="oninput" />
    </label>

    <label>
        City
        <input @bind="Shipping.City" />
    </label>

    <label>
        Zip Code
        <input @bind="Shipping.ZipCode" />
    </label>

    @if (!string.IsNullOrWhiteSpace(validationMessage))
    {
        <p class="validation-error">@validationMessage</p>
    }

    <button @onclick="GoNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    private string? validationMessage;

    private async Task GoNext()
    {
        if (string.IsNullOrWhiteSpace(Shipping.Name) || string.IsNullOrWhiteSpace(Shipping.Address))
        {
            validationMessage = "Name and Address are required.";
            return;
        }

        validationMessage = null;
        await OnNext.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-74dd4042feeb46259ae46f7b365591cc/CheckoutWizard.razor", "file_text": "<div class="checkout-wizard">
    <h2>Checkout (Step @step of 2)</h2>

    @if (step == 1)
    {
        <ShippingStep Shipping="order.Shipping" OnNext="GoToPayment" />
    }
    else
    {
        <PaymentStep Payment="order.Payment"
                     OnBack="GoToShipping"
                     OnPlaceOrder="PlaceOrder" />
    }
</div>

@code {
    /// <summary>Raised when the user completes the wizard and places the order.</summary>
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private readonly Order order = new();
    private int step = 1;

    private void GoToPayment() => step = 2;
    private void GoToShipping() => step = 1;

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(order);
    }
}
"}

